# Concrete shape implementations
from shapes_base import Shape, ShapeCategory, IDrawable

class Circle(Shape, IDrawable):
    radius: float

    def __init__(self, radius: float):
        super().__init__("Circle", ShapeCategory.GEOMETRIC)
        self.radius = radius

    @override
    def calculate_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def calculate_perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def draw(self) -> str:
        return f"Drawing circle with radius {self.radius}"

    @override
    def __str__(self) -> str:
        return f"Circle(r={self.radius})"

class Rectangle(Shape, IDrawable):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle", ShapeCategory.GEOMETRIC)
        self.width = width
        self.height = height

    @override
    def calculate_area(self) -> float:
        return self.width * self.height

    @override
    def calculate_perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def draw(self) -> str:
        return f"Drawing rectangle {self.width}x{self.height}"

    @override
    def __str__(self) -> str:
        return f"Rectangle({self.width}x{self.height})"

class Triangle(Shape, IDrawable):
    a: float
    b: float
    c: float

    def __init__(self, a: float, b: float, c: float):
        super().__init__("Triangle", ShapeCategory.GEOMETRIC)
        self.a = a
        self.b = b
        self.c = c

    @override
    def calculate_area(self) -> float:
        # Using Heron's formula
        s: float = self.calculate_perimeter() / 2.0
        return (s * (s - self.a) * (s - self.b) * (s - self.c)) ** 0.5

    @override
    def calculate_perimeter(self) -> float:
        return self.a + self.b + self.c

    def draw(self) -> str:
        return f"Drawing triangle with sides {self.a}, {self.b}, {self.c}"

    @override
    def __str__(self) -> str:
        return f"Triangle({self.a},{self.b},{self.c})"

