# Utility functions and struct for shape operations
from shapes_base import Shape, IDrawable
from shapes_concrete import Circle, Rectangle

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def __str__(self) -> str:
        return f"Point({self.x},{self.y})"

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total = total + shape.calculate_area()
    return total

def find_largest_shape(shapes: list[Shape]) -> Shape:
    largest: Shape = shapes[0]
    for shape in shapes:
        if shape.calculate_area() > largest.calculate_area():
            largest = shape
    return largest

def create_unit_circle() -> Circle:
    return Circle(1.0)

def create_square(side: float) -> Rectangle:
    return Rectangle(side, side)

# Using raw function type instead of type alias
def filter_shapes(shapes: list[Shape], predicate: (Shape) -> bool) -> list[Shape]:
    result: list[Shape] = []
    for shape in shapes:
        if predicate(shape):
            result.append(shape)
    return result

def is_large_shape(shape: Shape) -> bool:
    return shape.calculate_area() > 10.0

