# Controller classes that work with shapes across modules
from shapes_base import Shape, IDrawable, ShapeCategory, IMeasurable
from shapes_concrete import Circle, Rectangle, Triangle
from shape_utils import Point, calculate_total_area, filter_shapes, is_large_shape

class ShapeRenderer:
    def render(self, drawable: IDrawable) -> str:
        return drawable.draw()

    def render_all(self, drawables: list[IDrawable]) -> list[str]:
        results: list[str] = []
        for drawable in drawables:
            results.append(self.render(drawable))
        return results

@abstract
class ShapeFactory:
    @abstract
    def create_shape(self) -> Shape: ...

class CircleFactory(ShapeFactory):
    radius: float

    def __init__(self, radius: float):
        self.radius = radius

    @override
    def create_shape(self) -> Shape:
        return Circle(self.radius)

class RandomShapeGenerator:
    @static
    seed: int = 42

    @static
    def generate_count() -> int:
        return 3

    def generate_shapes(self) -> list[Shape]:
        shapes: list[Shape] = []
        shapes.append(Circle(2.0))
        shapes.append(Rectangle(3.0, 4.0))
        shapes.append(Triangle(3.0, 4.0, 5.0))
        return shapes

class ShapeAnalyzer:
    def analyze(self, shape: Shape) -> str:
        category: str = shape.get_category_name()
        area: float = shape.calculate_area()
        perimeter: float = shape.calculate_perimeter()
        result: str = f"{shape.name}: category={category}, area={area:.2f}, perimeter={perimeter:.2f}"
        return result

    def count_by_category(self, shapes: list[Shape], category: ShapeCategory) -> int:
        count: int = 0
        for shape in shapes:
            if shape.category == category:
                count = count + 1
        return count
